    /// <summary>時刻別スケジュールタイプを取得する</summary>
    /// <param name="cPattern"></param>
    /// <param name="dTime"></param>
    /// <returns></returns>
    public static HourlySchedule GetHourlyScheduleType(CalendarPattern cPattern, DateTime dTime)
    {
      int doy = dTime.DayOfYear;
      switch (cPattern)
      {
        case CalendarPattern.A:
          if (contains(doy, 1, 2, 3, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357, 363, 364, 365))
            return HourlySchedule.Type3;
          if (dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type3;
          if (dTime.DayOfWeek == DayOfWeek.Saturday) return HourlySchedule.Type2;
          return HourlySchedule.Type1;
        case CalendarPattern.B:
          if (contains(doy, 1, 2, 3, 363, 364, 365)) return HourlySchedule.Type3;
          if (contains(doy, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357)) return HourlySchedule.Type2;
          if (dTime.DayOfWeek == DayOfWeek.Saturday || dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type2;
          if (82 <= doy && doy <= 93) return HourlySchedule.Type2;
          if (205 <= doy && doy <= 243) return HourlySchedule.Type2;
          if (357 <= doy) return HourlySchedule.Type2;
          return HourlySchedule.Type1;
        case CalendarPattern.C:
          if (contains(doy, 1, 2, 3, 363, 364, 365)) return HourlySchedule.Type3;
          if (contains(doy, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357)) return HourlySchedule.Type2;
          if (dTime.DayOfWeek == DayOfWeek.Saturday || dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type2;
          if (4 <= doy && doy <= 9) return HourlySchedule.Type2;
          if (54 <= doy && doy <= 93) return HourlySchedule.Type2;
          if (205 <= doy && doy <= 266) return HourlySchedule.Type2;
          if (357 <= doy) return HourlySchedule.Type2;
          return HourlySchedule.Type1;
        case CalendarPattern.D:
          if (contains(doy, 1, 2, 3, 363, 364, 365)) return HourlySchedule.Type3;
          if (contains(doy, 5, 33, 61, 96, 131, 152, 187, 215, 250, 278, 306, 341)) return HourlySchedule.Type3;
          if (contains(doy, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357)) return HourlySchedule.Type2;
          if (dTime.DayOfWeek == DayOfWeek.Saturday || dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type2;
          return HourlySchedule.Type1;
        case CalendarPattern.E:
          if (contains(doy, 1, 2, 3, 363, 364, 365)) return HourlySchedule.Type3;
          if (contains(doy, 13, 127, 202, 267, 286, 328)) return HourlySchedule.Type3;
          if (contains(doy, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357)) return HourlySchedule.Type2;
          if (dTime.DayOfWeek == DayOfWeek.Monday) return HourlySchedule.Type3;
          if (dTime.DayOfWeek == DayOfWeek.Saturday || dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type2;
          return HourlySchedule.Type1;
        case CalendarPattern.F:
          if (dTime.DayOfWeek == DayOfWeek.Saturday || dTime.DayOfWeek == DayOfWeek.Sunday) return HourlySchedule.Type2;
          if (contains(doy, 1, 2, 363, 364, 365)) return HourlySchedule.Type3;
          if (contains(doy, 12, 42, 79, 119, 201, 264, 265, 266, 285, 307, 327, 357)) return HourlySchedule.Type2;
          if (19 <= doy && doy <= 30) return HourlySchedule.Type3;
          if (54 <= doy && doy <= 65) return HourlySchedule.Type3;
          if (82 <= doy && doy <= 93) return HourlySchedule.Type3;
          if (110 <= doy && doy <= 121) return HourlySchedule.Type3;
          if (138 <= doy && doy <= 149) return HourlySchedule.Type3;
          if (173 <= doy && doy <= 184) return HourlySchedule.Type3;
          if (202 <= doy && doy <= 212) return HourlySchedule.Type3;
          if (229 <= doy && doy <= 240) return HourlySchedule.Type3;
          if (267 <= doy && doy <= 275) return HourlySchedule.Type3;
          if (292 <= doy && doy <= 303) return HourlySchedule.Type3;
          if (328 <= doy && doy <= 338) return HourlySchedule.Type3;
          if (355 <= doy && doy <= 365) return HourlySchedule.Type3;
          return HourlySchedule.Type1;
        default:
          throw new ArgumentOutOfRangeException(nameof(cPattern), cPattern, "Unhandled CalendarPattern.");
      }
    }

    private static bool contains(int target, params int[] args)
    {
      for (int i = 0; i < args.Length; i++)
        if (target == args[i]) return true;

      return false;
    }

    /// <summary>空調を制御する</summary>
    /// <param name="zone">ゾーン</param>
    public void ControlACSystem(Zone zone)
    {
      GetACSetting(zone, out bool acMoves, out double dbSP, out double hrSP);

      if (acMoves)
      {
        zone.ControlDryBulbTemperature(dbSP);
        zone.ControlHumidityRatio(hrSP);
        zone.VentilationRate = schSet.VentilationRate * zone.FloorArea * 1.2 / 3600;
      }
      else
      {
        zone.ControlHeatSupply(0);
        zone.ControlMoistureSupply(0);
        zone.VentilationRate = AIR_LEAK_RATE * zone.AirMass / 3600d;
      }
    }

    /// <summary>空調設定を取得する</summary>
    /// <param name="zone">ゾーン</param>
    /// <param name="useAC">空調を稼働させるか否か</param>
    /// <param name="drybulbSetpoint">乾球温度設定値[C]</param>
    /// <param name="humidityRatioSetpoint">絶対湿度設定値[kg/kg]</param>
    /// <exception cref="Exception"></exception>
    public void GetACSetting(
      IReadOnlyZone zone,
      out bool useAC, out double drybulbSetpoint, out double humidityRatioSetpoint)
    {
      DateTime dt = zone.MultiRoom.CurrentDateTime;
      HourlySchedule st = GetHourlyScheduleType(Calendar, dt);

      //季節を判定
      if (dt.Month <= 3 || 12 == dt.Month)
      {
        drybulbSetpoint = schSet.SetpointTemperature_HeatingSeason;
        humidityRatioSetpoint = MoistAir.GetHumidityRatioFromDryBulbTemperatureAndRelativeHumidity
          (drybulbSetpoint, schSet.SetpointRHumidity_HeatingSeason, 101.325);
      }
      else if (6 <= dt.Month && dt.Month <= 9)
      {
        drybulbSetpoint = schSet.SetpointTemperature_CoolingSeason;
        humidityRatioSetpoint = MoistAir.GetHumidityRatioFromDryBulbTemperatureAndRelativeHumidity
          (drybulbSetpoint, schSet.SetpointRHumidity_CoolingSeason, 101.325);
      }
      else
      {
        drybulbSetpoint = schSet.SetpointTemperature_MidSeason;
        humidityRatioSetpoint = MoistAir.GetHumidityRatioFromDryBulbTemperatureAndRelativeHumidity
          (drybulbSetpoint, schSet.SetpointRHumidity_MidSeason, 101.325);
      }

      int sttH, endH;
      switch (st)
      {
        case HourlySchedule.Type1:
          sttH = schSet.ACStartHour_Type1;
          endH = schSet.ACEndHour_Type1;
          break;
        case HourlySchedule.Type2:
          sttH = schSet.ACStartHour_Type2;
          endH = schSet.ACEndHour_Type2;
          break;
        case HourlySchedule.Type3:
          sttH = schSet.ACStartHour_Type3;
          endH = schSet.ACEndHour_Type3;
          break;
        default: throw new InvalidOperationException("Unhandled HourlySchedule.");
      }
      if (sttH < endH) useAC = (sttH <= dt.Hour && dt.Hour < endH);
      else useAC = dt.Hour < endH || sttH <= dt.Hour;
      if (sttH == endH) useAC = false;
    }

    #endregion

    #region IHeatGain実装

    private double getSensibleHeatGain(IReadOnlyZone zone)
    {
      DateTime dt = zone.MultiRoom.CurrentDateTime;
      HourlySchedule st = GetHourlyScheduleType(Calendar, dt);

      double sHeat;
      switch (st)
      {
        case HourlySchedule.Type1:
          sHeat = schSet.ReferenceLightingLoad * schSet.LightRatio_Type1[dt.Hour]
            + schSet.ReferenceOccupancyLoad * OCC_SENSIBLE_RATE * schSet.OccupancyRatio_Type1[dt.Hour]
            + schSet.ReferencePlugLoad * schSet.PlugRatio_Type1[dt.Hour];
          break;
        case HourlySchedule.Type2:
          sHeat = schSet.ReferenceLightingLoad * schSet.LightRatio_Type2[dt.Hour]
            + schSet.ReferenceOccupancyLoad * OCC_SENSIBLE_RATE * schSet.OccupancyRatio_Type2[dt.Hour]
            + schSet.ReferencePlugLoad * schSet.PlugRatio_Type2[dt.Hour];
          break;
        case HourlySchedule.Type3:
          sHeat = schSet.ReferenceLightingLoad * schSet.LightRatio_Type3[dt.Hour]
            + schSet.ReferenceOccupancyLoad * OCC_SENSIBLE_RATE * schSet.OccupancyRatio_Type3[dt.Hour]
            + schSet.ReferencePlugLoad * schSet.PlugRatio_Type3[dt.Hour];
          break;
        default: throw new InvalidOperationException("Unhandled HourlySchedule.");
      }
      return zone.FloorArea * sHeat;

    }

    /// <summary>顕熱取得[W]の内、対流成分を取得する</summary>
    /// <param name="zone">発熱要素が属するゾーン</param>
    /// <returns>顕熱取得の対流成分[kW]</returns>
    public double GetConvectiveHeatGain(IReadOnlyZone zone) 
    {
      return getSensibleHeatGain(zone) * (1 - RADIATION_RATE);
    }

    /// <summary>顕熱取得[W]の内、放射成分を取得する</summary>
    /// <param name="zone">発熱要素が属するゾーン</param>
    /// <returns>顕熱取得の放射成分[kW]</returns>
    public double GetRadiativeHeatGain(IReadOnlyZone zone) 
    {
      return getSensibleHeatGain(zone) * RADIATION_RATE;
    }

    /// <summary>発生水分[kg/s]を取得する</summary>
    /// <param name="zone">発熱要素が属するゾーン</param>
    /// <returns>発生水分[kg/s]</returns>
    public double GetMoistureGain(IReadOnlyZone zone)
    {
      DateTime dt = zone.MultiRoom.CurrentDateTime;
      HourlySchedule st = GetHourlyScheduleType(Calendar, dt);

      double lHeat;
      switch (st)
      {
        case HourlySchedule.Type1:
          lHeat = schSet.ReferenceOccupancyLoad * (1d - OCC_SENSIBLE_RATE) * schSet.OccupancyRatio_Type1[dt.Hour];
          break;
        case HourlySchedule.Type2:
          lHeat = schSet.ReferenceOccupancyLoad * (1d - OCC_SENSIBLE_RATE) * schSet.OccupancyRatio_Type2[dt.Hour];
          break;
        case HourlySchedule.Type3:
          lHeat = schSet.ReferenceOccupancyLoad * (1d - OCC_SENSIBLE_RATE) * schSet.OccupancyRatio_Type3[dt.Hour];
          break;
        default: throw new InvalidOperationException("Unhandled HourlySchedule.");
      }
      return zone.FloorArea * lHeat / 2500000d;
    }

