      /// <summary>照明負荷比率（Type1）[-]を取得する</summary>
      public double[] LightRatio_Type1 { get; private set; }

      /// <summary>照明負荷比率（Type2）[-]を取得する</summary>
      public double[] LightRatio_Type2 { get; private set; }

      /// <summary>照明負荷比率（Type3）[-]を取得する</summary>
      public double[] LightRatio_Type3 { get; private set; }

      /// <summary>人体負荷比率（Type1）[-]を取得する</summary>
      public double[] OccupancyRatio_Type1 { get; private set; }

      /// <summary>人体負荷比率（Type2）[-]を取得する</summary>
      public double[] OccupancyRatio_Type2 { get; private set; }

      /// <summary>人体負荷比率（Type3）[-]を取得する</summary>
      public double[] OccupancyRatio_Type3 { get; private set; }

      /// <summary>コンセント負荷比率（Type1）[-]を取得する</summary>
