        double setpointTemperature_CoolingSeason, double setpointTemperature_MidSeason, double setpointTemperature_HeatingSeason,
        double setpointRHumidity_CoolingSeason, double setpointRHumidity_MidSeason, double setpointRHumidity_HeatingSeason,
        int acStartHour_Type1, int acStartHour_Type2, int acStartHour_Type3,
